var currentModel = {};
function fmt(n) {
  return '£' + Number(n).toFixed(2);
}
function render(model) {
  currentModel = model;
  var fees = Array.isArray(model.fees) ? model.fees : [];
  var totalFees = fees.reduce(function (sum, f) {
    return sum + Number(f.fee_amount || 0);
  }, 0);
  var carriage = Number(model.carriage || 0);
  var sellPrice = Number(model.sell_price || 0);
  var originalCost = Number(model.original_cost || 0);
  var partsCost = Number(model.parts_cost || 0);
  var erasureStatus = model.erasure_status || '';
  var erasureFee = Number(model.erasure_fee || 0);
  var totalDeductions = totalFees + carriage + partsCost + erasureFee;
  var profit = sellPrice - originalCost - totalDeductions;
  var ic = document.getElementById('input_cost');
  var is = document.getElementById('input_sell');
  if (ic && !ic.matches(':focus')) ic.value = originalCost ? originalCost.toFixed(2) : '';
  if (is && !is.matches(':focus')) is.value = sellPrice ? sellPrice.toFixed(2) : '';
  var vFees = document.getElementById('v_fees');
  var vCarriage = document.getElementById('v_carriage');
  var vParts = document.getElementById('v_parts');
  var vErasure = document.getElementById('v_erasure');
  var vErasureBadge = document.getElementById('v_erasure_badge');
  var vCost = document.getElementById('v_cost');
  var vSell = document.getElementById('v_sell');
  var vDeductions = document.getElementById('v_deductions');
  var vProfit = document.getElementById('v_profit');
  var vSaleBtn = document.getElementById('view_sale_btn');
  if (vFees) vFees.textContent = fmt(totalFees);
  if (vCarriage) vCarriage.textContent = fmt(carriage);
  if (vParts) vParts.textContent = fmt(partsCost);
  if (vErasure) vErasure.textContent = fmt(erasureFee);
  if (vErasureBadge) {
    vErasureBadge.innerHTML = erasureFee > 0 ? '<span class="erasure-badge b-erased">Auto £' + erasureFee.toFixed(2) + '</span>' : '<span class="erasure-badge b-pending">Pending</span>';
  }
  if (vCost) vCost.textContent = fmt(originalCost);
  if (vSell) vSell.textContent = fmt(sellPrice);
  if (vDeductions) vDeductions.textContent = fmt(totalDeductions);
  if (vProfit) {
    vProfit.textContent = fmt(profit);
    vProfit.className = 'profit-value ' + (profit >= 0 ? 'positive' : 'negative');
  }
  if (vSaleBtn) {
    vSaleBtn.style.display = model.status_name === 'Sold' && model.sale_id ? 'block' : 'none';
  }
}
window.saveCost = function () {
  var ic = document.getElementById('input_cost');
  appsmith.updateModel({
    input_cost: ic ? parseFloat(ic.value) || 0 : 0
  });
  appsmith.triggerEvent('onSaveCost');
};
window.saveSell = function () {
  var is = document.getElementById('input_sell');
  appsmith.updateModel({
    input_sell: is ? parseFloat(is.value) || 0 : 0
  });
  appsmith.triggerEvent('onSaveSell');
};
window.viewSale = function () {
  appsmith.updateModel({
    sale_id: currentModel.sale_id
  });
  appsmith.triggerEvent('onViewSale');
};
appsmith.onReady(function () {
  render(appsmith.model);
});
appsmith.onModelChange(function (model) {
  render(model);
});

